// Extract lesson completion data
const eventData = $input.first().json;
const userId = eventData.user_id;
const lessonData = eventData.data;
const eventType = eventData.event_type;

// Determine completion type and celebration level
let completionType = 'standard';
let celebrationLevel = 'normal';
let rewardMultiplier = 1;
let congratulationsMessage = '';

if (eventType === 'progress.milestone') {
  completionType = 'milestone';
  celebrationLevel = 'high';
  rewardMultiplier = 2;
  congratulationsMessage = `🎉 Amazing milestone! You've completed ${lessonData.total_completed_lessons} lessons! Keep up the fantastic work!`;
} else {
  const score = lessonData.score || 0;
  if (score >= 90) {
    completionType = 'excellent';
    celebrationLevel = 'high';
    rewardMultiplier = 1.5;
    congratulationsMessage = '🌟 Outstanding performance! You truly mastered this lesson!';
  } else if (score >= 80) {
    completionType = 'good';
    celebrationLevel = 'normal';
    congratulationsMessage = '👏 Well done! You showed great understanding of the concepts!';
  } else if (score >= 70) {
    completionType = 'satisfactory';
    congratulationsMessage = '✨ Good job completing the lesson! Practice makes perfect!';
  } else {
    completionType = 'needs_review';
    congratulationsMessage = '💪 Lesson completed! Consider reviewing the material to strengthen your understanding.';
  }
}

// Calculate base rewards
const basePoints = lessonData.time_spent_minutes ? Math.min(100, lessonData.time_spent_minutes * 2) : 50;
const bonusPoints = Math.round(basePoints * (rewardMultiplier - 1));

return [{
  json: {
    user_id: userId,
    lesson_id: lessonData.lesson_id,
    completion_type: completionType,
    celebration_level: celebrationLevel,
    score: lessonData.score || 0,
    time_spent: lessonData.time_spent_minutes || 0,
    total_completed: lessonData.total_completed_lessons || 0,
    skill_level: lessonData.skill_level || 'beginner',
    congratulations_message: congratulationsMessage,
    rewards: {
      base_points: basePoints,
      bonus_points: bonusPoints,
      total_points: basePoints + bonusPoints,
      reward_multiplier: rewardMultiplier
    },
    is_milestone: eventType === 'progress.milestone',
    timestamp: new Date().toISOString()
  }
}];
